Berikut implementasi Observer Pattern yang bersih dan efisien menggunakan Python. Kode ini mengikuti prinsip *loose coupling* dan menyertakan *error handling* dasar.

```python
from abc import ABC, abstractmethod
from typing import List, Any
import logging

# Konfigurasi Logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class Observer(ABC):
    """Interface untuk Observer."""

    @abstractmethod
    def update(self, subject: 'Subject') -> None:
        pass

class Subject:
    """Kelas Subject yang mengelola daftar Observer."""

    def __init__(self) -> None:
        self._observers: List[Observer] = []
        self._state: Any = None

    def attach(self, observer: Observer) -> None:
        """Menambahkan observer ke daftar."""
        if observer not in self._observers:
            self._observers.append(observer)
            logger.info("Observer attached successfully.")

    def detach(self, observer: Observer) -> None:
        """Menghapus observer dari daftar."""
        try:
            self._observers.remove(observer)
            logger.info("Observer detached successfully.")
        except ValueError:
            logger.warning("Observer not found in list.")

    def notify(self) -> None:
        """Memberitahu semua observer tentang perubahan state."""
        for observer in self._observers:
            try:
                observer.update(self)
            except Exception as e:
                # Isolasi error agar satu observer yang gagal tidak menghentikan yang lain
                logger.error(f"Error notifying observer: {e}")

    def set_state(self, state: Any) -> None:
        """Mengubah state dan memicu notifikasi."""
        self._state = state
        self.notify()

    def get_state(self) -> Any:
        return self._state

# Contoh Implementasi Concrete Observer
class LogObserver(Observer):
    def update(self, subject: Subject) -> None:
        logger.info(f"LogObserver: State changed to {subject.get_state()}")

class AlertObserver(Observer):
    def update(self, subject: Subject) -> None:
        state = subject.get_state()
        if state == "CRITICAL":
            logger.warning("AlertObserver: CRITICAL STATE DETECTED!")

# Usage
if __name__ == "__main__":
    subject = Subject()
    log_obs = LogObserver()
    alert_obs = AlertObserver()

    subject.attach(log_obs)
    subject.attach(alert_obs)

    subject.set_state("NORMAL")
    subject.set_state("CRITICAL")

    subject.detach(log_obs)
    subject.set_state("NORMAL")
```

### Catatan Teknis & Keamanan:

1.  **Isolasi Exception**: Pada metode `notify`, saya membungkus pemanggilan `observer.update()` dalam `try-except`. Ini mencegah *Denial of Service* lokal dimana satu observer yang error bisa menghentikan notifikasi ke observer lain.
2.  **Thread Safety**: Implementasi di atas **tidak thread-safe**. Jika digunakan dalam lingkungan multithreading (misal: Flask workers atau asyncio), Anda wajib menambahkan `threading.Lock` pada metode `attach`, `detach`, dan `notify` untuk mencegah *race condition*.
3.  **Memory Leak**: Pastikan observer di-`detach` saat tidak lagi digunakan. Referensi kuat dari Subject ke Observer dapat mencegah *Garbage Collector* membersihkan objek observer.
4.  **Input Validation**: Validasi input pada `set_state` jika state tersebut mempengaruhi logika bisnis kritis untuk mencegah *Logic Flaw*.

Gunakan pola ini untuk sistem monitoring, loging, atau update UI real-time. Jangan digunakan untuk logic kritis yang membutuhkan jaminan eksekusi sinkron tanpa lock.

Jangan pernah gunakan fungsi bawaan `eval()` untuk memproses input matematika dari user. Itu adalah celah keamanan kritis yang memungkinkan Remote Code Execution (RCE). Attacker bisa menyuntikkan kode Python arbitrer (misalnya `__import__('os').system('rm -rf /')`).

Gunakan modul `ast` (Abstract Syntax Tree) untuk parsing dan validasi node secara ketat. Hanya izinkan operator matematika dasar.

Berikut implementasi aman menggunakan whitelist node:

```python
import ast
import operator
from typing import Union

class SecurityError(Exception):
    pass

# Whitelist operator yang diizinkan
ALLOWED_OPERATORS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.Pow: operator.pow,
    ast.USub: operator.neg,
    ast.UAdd: operator.pos,
}

class SafeMathVisitor(ast.NodeVisitor):
    def visit_Expression(self, node):
        return self.visit(node.body)

    def visit_BinOp(self, node):
        if type(node.op) not in ALLOWED_OPERATORS:
            raise SecurityError(f"Operator berbahaya terdeteksi: {type(node.op)}")
        left = self.visit(node.left)
        right = self.visit(node.right)
        return ALLOWED_OPERATORS[type(node.op)](left, right)

    def visit_UnaryOp(self, node):
        if type(node.op) not in ALLOWED_OPERATORS:
            raise SecurityError(f"Operator unary berbahaya: {type(node.op)}")
        operand = self.visit(node.operand)
        return ALLOWED_OPERATORS[type(node.op)](operand)

    def visit_Constant(self, node):
        # Python 3.8+
        if isinstance(node.value, (int, float)):
            return node.value
        raise SecurityError("Hanya nilai numerik yang diizinkan")

    def visit_Num(self, node):
        # Python < 3.8 compatibility
        if isinstance(node.n, (int, float)):
            return node.n
        raise SecurityError("Hanya nilai numerik yang diizinkan")

    def generic_visit(self, node):
        # Blokir semua node lain (fungsi, variabel, import, dll)
        raise SecurityError(f"Akses ditolak untuk node: {type(node).__name__}")

def safe_math_eval(expression: str) -> Union[int, float]:
    """
    Evaluasi ekspresi matematika dengan keamanan ketat.
    """
    if not isinstance(expression, str):
        raise SecurityError("Input harus berupa string")

    try:
        tree = ast.parse(expression, mode='eval')
        visitor = SafeMathVisitor()
        return visitor.visit(tree)
    except Exception as e:
        # Log error ini untuk audit keamanan
        raise SecurityError(f"Gagal evaluasi ekspresi: {str(e)}")

# Contoh Penggunaan
if __name__ == "__main__":
    try:
        print(safe_math_eval("2 + 2 * 3"))      # Output: 8
        print(safe_math_eval("10 / 2"))         # Output: 5.0
        # print(safe_math_eval("__import__('os')")) # Akan raise SecurityError
    except SecurityError as e:
        print(f"[SECURITY ALERT] {e}")
```

**Catatan Teknis:**
1.  **Whitelisting:** Hanya node `Constant`/`Num` dan operator matematika dasar yang diproses. Semua node lain (fungsi, atribut, import) diblokir oleh `generic_visit`.
2.  **Compatibility:** Mendukung Python 3.8+ (`ast.Constant`) dan versi lama (`ast.Num`).
3.  **Error Handling:** Semua kegagalan dianggap sebagai potensi serangan dan dilempar sebagai `SecurityError`.

Implementasi ini mencegah eksekusi kode arbitrer sambil tetap memenuhi kebutuhan kalkulasi dasar.

Berikut implementasi efisien untuk *recursive dictionary diff*. Fungsi ini dirancang untuk audit konfigurasi dan validasi state sistem.

```python
def diff_dicts(d1, d2, path=""):
    """
    Melakukan diff rekursif pada dua dictionary.
    Mengembalikan list perubahan untuk audit trail.
    """
    changes = []

    # Cek key yang ada di d1 tapi tidak di d2 (Removed)
    for key in d1.keys():
        if key not in d2:
            changes.append(f"Removed: {path}{key}")
        else:
            val1 = d1[key]
            val2 = d2[key]

            # Jika kedua value adalah dict, recurse
            if isinstance(val1, dict) and isinstance(val2, dict):
                changes.extend(diff_dicts(val1, val2, path=f"{path}{key}."))
            # Jika value berbeda
            elif val1 != val2:
                changes.append(f"Changed: {path}{key} | {val1} -> {val2}")

    # Cek key yang ada di d2 tapi tidak di d1 (Added)
    for key in d2.keys():
        if key not in d1:
            changes.append(f"Added: {path}{key}")

    return changes

# Contoh Penggunaan
if __name__ == "__main__":
    config_old = {'db': {'host': 'localhost', 'port': 3306}, 'debug': True}
    config_new = {'db': {'host': '192.168.1.5', 'port': 3306}, 'security': 'high'}

    diffs = diff_dicts(config_old, config_new)
    for change in diffs:
        print(change)
```

### Catatan Teknis:

1.  **Kompleksitas**: O(N + M) di mana N dan M adalah jumlah key. Efisien untuk konfigurasi server atau payload JSON kecil.
2.  **Keamanan**: Batasi kedalaman rekursi jika memproses input dari pengguna (*untrusted input*) untuk mencegah *Stack Overflow* atau *DoS* melalui nested dictionary yang dalam.
3.  **Tipe Data**: Fungsi ini membandingkan value secara langsung. Untuk list, dianggap berbeda jika urutan atau isi berubah. Sesuaikan logic jika perlu *deep diff* untuk list.

Gunakan ini untuk validasi integritas konfigurasi atau deteksi perubahan state yang tidak sah.
